"use strict";(self.webpackChunkleetcode=self.webpackChunkleetcode||[]).push([[7161],{8896:e=>{e.exports=JSON.parse('{"tag":{"label":"matrix","permalink":"/leetcode/docs/tags/matrix","allTagsPath":"/leetcode/docs/tags","count":13,"items":[{"id":"problems/friend-circles","title":"Friend Circles","description":"This question is asked by Facebook. You are given a two dimensional matrix, friends, that represents relationships between coworkers in an office. If friendsi = 1 then coworker i is friends with coworker j and coworker j is friends with coworker i. Similarly if friendsi = 0 then coworker i is not friends with coworker j and coworker j is not friend with coworker i. Friendships in the office are transitive (i.e., if coworker one is friends with coworker two and coworker two is friends with coworker three, coworker one is also friends with coworker three). Given the friendships in the office defined by friends, return the total number of distinct friends groups in the office.","permalink":"/leetcode/docs/problems/friend-circles"},{"id":"problems/largest-pond-size","title":"Largest Pond Size","description":"You are given a two-dimensional matrix that represents a plot of land. Within the matrix there exist two values: ones which represent land and zeroes which represent water within a pond. Given that parts of a pond can be connected both horizontally and vertically (but not diagonally), return the largest pond size.","permalink":"/leetcode/docs/problems/largest-pond-size"},{"id":"problems/max-area-of-island","title":"Max Area of Island","description":"Given a 2D array grid, where zeroes represent water and ones represent land, return the size of the largest island.","permalink":"/leetcode/docs/problems/max-area-of-island"},{"id":"problems/minimum-path-sum","title":"Minimum Path Sum","description":"This question is asked by Google. Given an N\xd7M matrix, grid, where each cell in the matrix represents the cost of stepping on the current cell, return the minimum cost to traverse from the top-left hand corner of the matrix to the bottom-right hand corner.","permalink":"/leetcode/docs/problems/minimum-path-sum"},{"id":"problems/number-of-islands","title":"Number of Islands","description":"Given a 2D array of integers with ones representing land and zeroes representing water, return the number of islands in the grid.","permalink":"/leetcode/docs/problems/number-of-islands"},{"id":"problems/number-of-ships","title":"Number of Ships in Harbor","description":"You\'re about to set sail off a pier and first want to count the number of ships that are already in the harbor. The harbor is deemed safe to sail in if the number of boats in the harbor is strictly less than limit. Given a 2D array that presents the harbor, where O represents water and S represents a ship, return whether or not it\'s safe for you to set sail.","permalink":"/leetcode/docs/problems/number-of-ships"},{"id":"problems/path-with-maximum-gold","title":"Path with Maximum Gold","description":"This question is asked by Amazon. Given a 2D matrix that represents a gold mine, where each cell\'s value represents an amount of gold, return the maximum amount of gold you can collect given the following rules:","permalink":"/leetcode/docs/problems/path-with-maximum-gold"},{"id":"problems/rabbit-holes","title":"Rabbit Holes Distance","description":"Given a 2D array containing only the following values: -1, 0, 1 where -1 represents an obstacle, 0 represents a rabbit hole, and 1 represents a rabbit, update every cell containing a rabbit with the distance to its closest rabbit hole.","permalink":"/leetcode/docs/problems/rabbit-holes"},{"id":"problems/rotate-image","title":"Rotate Image","description":"Given an image represented as a 2D array of pixels, return the image rotated 90 degrees clockwise.","permalink":"/leetcode/docs/problems/rotate-image"},{"id":"problems/rotting-oranges","title":"Rotting Oranges (Infection Spread)","description":"Given a 2D array where each cell can have one of three values:","permalink":"/leetcode/docs/problems/rotting-oranges"},{"id":"problems/spiral-matrix","title":"Spiral Matrix","description":"Given a 2D matrix, return a list containing all of its elements in spiral order.","permalink":"/leetcode/docs/problems/spiral-matrix"},{"id":"problems/transpose-matrix","title":"Transpose Matrix","description":"Given a 2D matrix nums, return the matrix transposed.","permalink":"/leetcode/docs/problems/transpose-matrix"},{"id":"problems/word-search","title":"Word Search","description":"This question is asked by Amazon. Given a 2D board that represents a word search puzzle and a string word, return whether or the given word can be formed in the puzzle by only connecting cells horizontally and vertically.","permalink":"/leetcode/docs/problems/word-search"}],"unlisted":false}}')}}]);